<?php require 'config/config.php'; require 'config/Database.php'; $db = Database::getInstance(); $db->query('SELECT pa.*, f.numero_ficha, u.nombre as instructor_nombre, u.apellido as instructor_apellido, a.nombre_ambiente as ambiente_nombre, d.nombre_dia, ra.codigo_resultado as ra_codigo, ra.descripcion as ra_descripcion, c.nombre_competencia as competencia_nombre FROM programacion_academica pa INNER JOIN fichas f ON pa.numero_ficha = f.numero_ficha INNER JOIN usuarios u ON pa.id_usuario = u.id_usuario INNER JOIN ambientes a ON pa.id_numero_ambiente = a.id_numero_ambiente INNER JOIN dias d ON pa.id_dias = d.id_dias INNER JOIN resultado_aprendizaje ra ON pa.id_resultado_aprendizaje = ra.id_resultado_aprendizaje INNER JOIN competencias c ON ra.id_competencia = c.id_competencia WHERE pa.id_numero_ambiente = 1 ORDER BY pa.fecha_inicio DESC, pa.hora_inicio'); print_r($db->resultSet()); ?>
